97	/// Types that are pointed to by a single word.
98	///
99	/// In concurrent programming, it is necessary to represent an object within a word because atomic
100	/// operations (e.g., reads, writes, read-modify-writes) support only single words.  This trait
101	/// qualifies such types that are pointed to by a single word.
102	///
103	/// The trait generalizes `Box<T>` for a sized type `T`.  In a box, an object of type `T` is
104	/// allocated in heap and it is owned by a single-word pointer.  This trait is also implemented for
105	/// `[MaybeUninit<T>]` by storing its size along with its elements and pointing to the pair of array
106	/// size and elements.
107	///
108	/// Pointers to `Pointable` types can be stored in [`Atomic`], [`Owned`], and [`Shared`].  In
109	/// particular, Crossbeam supports dynamically sized slices as follows.
110	///
111	/// ```
112	/// use std::mem::MaybeUninit;
113	/// use crossbeam_epoch::Owned;
114	///
115	/// let o = Owned::<[MaybeUninit<i32>]>::init(10); // allocating [i32; 10]
116	/// ```
117	pub trait Pointable {
118	    /// The alignment of pointer.
119	    const ALIGN: usize;
120	
121	    /// The type for initializers.
122	    type Init;
123	
124	    /// Initializes a with the given initializer.
125	    ///
126	    /// # Safety
127	    ///
128	    /// The result should be a multiple of `ALIGN`.
129	    unsafe fn init(init: Self::Init) -> *mut ();
130	
131	    /// Gets the raw pointer to this type that allows immutable access from the given pointer.
132	    ///
133	    /// # Safety
134	    ///
135	    /// - The given `ptr` should have been initialized with [`Pointable::init`].
136	    /// - `ptr` should not have yet been dropped by [`Pointable::drop`].
137	    /// - `ptr` should not be mutably dereferenced by [`Pointable::as_mut_ptr`] concurrently.
138	    unsafe fn as_ptr(ptr: *mut ()) -> *const Self;
139	
140	    /// Gets the raw pointer to this type that allows mutable access from the given pointer.
141	    ///
142	    /// # Safety
143	    ///
144	    /// - The given `ptr` should have been initialized with [`Pointable::init`].
145	    /// - `ptr` should not have yet been dropped by [`Pointable::drop`].
146	    /// - `ptr` should not be dereferenced by [`Pointable::as_ptr`] or [`Pointable::as_mut_ptr`]
147	    ///   concurrently.
148	    unsafe fn as_mut_ptr(ptr: *mut ()) -> *mut Self;
149	
150	    /// Drops the object pointed to by the given pointer.
151	    ///
152	    /// # Safety
153	    ///
154	    /// - The given `ptr` should have been initialized with [`Pointable::init`].
155	    /// - `ptr` should not have yet been dropped by [`Pointable::drop`].
156	    /// - `ptr` should not be dereferenced by [`Pointable::as_ptr`] or [`Pointable::as_mut_ptr`]
157	    ///   concurrently.
158	    unsafe fn drop(ptr: *mut ());
159	}
160	
161	impl<T> Pointable for T {
162	    const ALIGN: usize = mem::align_of::<T>();
163	
164	    type Init = T;
165	
166	    unsafe fn init(init: Self::Init) -> *mut () {
167	        Box::into_raw(Box::new(init)).cast::<()>()
168	    }
169	
170	    unsafe fn as_ptr(ptr: *mut ()) -> *const Self {
171	        ptr as *const T
172	    }
173	
174	    unsafe fn as_mut_ptr(ptr: *mut ()) -> *mut Self {
175	        ptr.cast::<T>()
176	    }
177	
178	    unsafe fn drop(ptr: *mut ()) {
179	        drop(unsafe { Box::from_raw(ptr.cast::<T>()) });
180	    }
181	}
