265	/// An atomic pointer that can be safely shared between threads.
266	///
267	/// The pointer must be properly aligned. Since it is aligned, a tag can be stored into the unused
268	/// least significant bits of the address. For example, the tag for a pointer to a sized type `T`
269	/// should be less than `(1 << mem::align_of::<T>().trailing_zeros())`.
270	///
271	/// Any method that loads the pointer must be passed a reference to a [`Guard`].
272	///
273	/// Crossbeam supports dynamically sized types.  See [`Pointable`] for details.
274	pub struct Atomic<T: ?Sized + Pointable> {
275	    data: AtomicPtr<()>,
276	    _marker: PhantomData<*mut T>,
277	}
278	
279	unsafe impl<T: ?Sized + Pointable + Send + Sync> Send for Atomic<T> {}
280	unsafe impl<T: ?Sized + Pointable + Send + Sync> Sync for Atomic<T> {}
281	
282	impl<T> Atomic<T> {
283	    /// Allocates `value` on the heap and returns a new atomic pointer pointing to it.
284	    ///
285	    /// # Examples
286	    ///
287	    /// ```
288	    /// use crossbeam_epoch::Atomic;
289	    ///
290	    /// let a = Atomic::new(1234);
291	    /// # unsafe { drop(a.into_owned()); } // avoid leak
292	    /// ```
293	    pub fn new(init: T) -> Self {
294	        Self::init(init)
295	    }
296	}
297	
298	impl<T: ?Sized + Pointable> Atomic<T> {
299	    /// Allocates `value` on the heap and returns a new atomic pointer pointing to it.
300	    ///
301	    /// # Examples
302	    ///
303	    /// ```
304	    /// use crossbeam_epoch::Atomic;
305	    ///
306	    /// let a = Atomic::<i32>::init(1234);
307	    /// # unsafe { drop(a.into_owned()); } // avoid leak
308	    /// ```
309	    pub fn init(init: T::Init) -> Self {
310	        Self::from(Owned::init(init))
311	    }
312	
313	    /// Returns a new atomic pointer pointing to the tagged pointer `data`.
314	    fn from_ptr(data: *mut ()) -> Self {
315	        Self {
316	            data: AtomicPtr::new(data),
317	            _marker: PhantomData,
318	        }
319	    }
320	
321	    const_fn! {
322	        const_if: #[cfg(not(crossbeam_loom))];
323	        /// Returns a new null atomic pointer.
324	        ///
325	        /// # Examples
326	        ///
327	        /// ```
328	        /// use crossbeam_epoch::Atomic;
329	        ///
330	        /// let a = Atomic::<i32>::null();
331	        /// ```
332	        pub const fn null() -> Self {
333	            Self {
334	                data: AtomicPtr::new(ptr::null_mut()),
335	                _marker: PhantomData,
336	            }
337	        }
338	    }
339	
340	    /// Loads a `Shared` from the atomic pointer.
341	    ///
342	    /// This method takes an [`Ordering`] argument which describes the memory ordering of this
343	    /// operation.
344	    ///
345	    /// # Examples
346	    ///
347	    /// ```
348	    /// use crossbeam_epoch::{self as epoch, Atomic};
349	    /// use std::sync::atomic::Ordering::SeqCst;
350	    ///
351	    /// let a = Atomic::new(1234);
352	    /// let guard = &epoch::pin();
353	    /// let p = a.load(SeqCst, guard);
354	    /// # unsafe { drop(a.into_owned()); } // avoid leak
355	    /// ```
356	    pub fn load<'g>(&self, order: Ordering, _: &'g Guard) -> Shared<'g, T> {
357	        unsafe { Shared::from_ptr(self.data.load(order)) }
358	    }
359	
360	    /// Loads a `Shared` from the atomic pointer using a "consume" memory ordering.
361	    ///
362	    /// This is similar to the "acquire" ordering, except that an ordering is
363	    /// only guaranteed with operations that "depend on" the result of the load.
364	    /// However consume loads are usually much faster than acquire loads on
365	    /// architectures with a weak memory model since they don't require memory
366	    /// fence instructions.
367	    ///
368	    /// The exact definition of "depend on" is a bit vague, but it works as you
369	    /// would expect in practice since a lot of software, especially the Linux
370	    /// kernel, rely on this behavior.
371	    ///
372	    /// # Examples
373	    ///
374	    /// ```
375	    /// use crossbeam_epoch::{self as epoch, Atomic};
376	    ///
377	    /// let a = Atomic::new(1234);
378	    /// let guard = &epoch::pin();
379	    /// let p = a.load_consume(guard);
380	    /// # unsafe { drop(a.into_owned()); } // avoid leak
381	    /// ```
382	    pub fn load_consume<'g>(&self, _: &'g Guard) -> Shared<'g, T> {
383	        unsafe { Shared::from_ptr(self.data.load_consume()) }
384	    }
385	
386	    /// Stores a `Shared` or `Owned` pointer into the atomic pointer.
387	    ///
388	    /// This method takes an [`Ordering`] argument which describes the memory ordering of this
389	    /// operation.
390	    ///
391	    /// # Examples
392	    ///
393	    /// ```
394	    /// use crossbeam_epoch::{Atomic, Owned, Shared};
395	    /// use std::sync::atomic::Ordering::SeqCst;
396	    ///
397	    /// let a = Atomic::new(1234);
398	    /// # unsafe { drop(a.load(SeqCst, &crossbeam_epoch::pin()).into_owned()); } // avoid leak
399	    /// a.store(Shared::null(), SeqCst);
400	    /// a.store(Owned::new(1234), SeqCst);
401	    /// # unsafe { drop(a.into_owned()); } // avoid leak
402	    /// ```
403	    pub fn store<P: Pointer<T>>(&self, new: P, order: Ordering) {
404	        self.data.store(new.into_ptr(), order);
405	    }
406	
407	    /// Stores a `Shared` or `Owned` pointer into the atomic pointer, returning the previous
408	    /// `Shared`.
409	    ///
410	    /// This method takes an [`Ordering`] argument which describes the memory ordering of this
411	    /// operation.
412	    ///
413	    /// # Examples
414	    ///
415	    /// ```
416	    /// use crossbeam_epoch::{self as epoch, Atomic, Shared};
417	    /// use std::sync::atomic::Ordering::SeqCst;
418	    ///
419	    /// let a = Atomic::new(1234);
420	    /// let guard = &epoch::pin();
421	    /// let p = a.swap(Shared::null(), SeqCst, guard);
422	    /// # unsafe { drop(p.into_owned()); } // avoid leak
423	    /// ```
424	    pub fn swap<'g, P: Pointer<T>>(&self, new: P, order: Ordering, _: &'g Guard) -> Shared<'g, T> {
425	        unsafe { Shared::from_ptr(self.data.swap(new.into_ptr(), order)) }
426	    }
427	
428	    /// Stores the pointer `new` (either `Shared` or `Owned`) into the atomic pointer if the current
429	    /// value is the same as `current`. The tag is also taken into account, so two pointers to the
430	    /// same object, but with different tags, will not be considered equal.
431	    ///
432	    /// The return value contains both the previous value and the new value that was written.
433	    /// On success, `old` contains the previous value (which equals `current`) and `new` contains
434	    /// the value that was stored. On failure, `old` contains the actual current value and `new`
435	    /// contains the value that was attempted to be stored.
436	    ///
437	    /// This method takes two `Ordering` arguments to describe the memory
438	    /// ordering of this operation. `success` describes the required ordering for the
439	    /// read-modify-write operation that takes place if the comparison with `current` succeeds.
440	    /// `failure` describes the required ordering for the load operation that takes place when
441	    /// the comparison fails. Using `Acquire` as success ordering makes the store part
442	    /// of this operation `Relaxed`, and using `Release` makes the successful load
443	    /// `Relaxed`. The failure ordering can only be `SeqCst`, `Acquire` or `Relaxed`
444	    /// and must be equivalent to or weaker than the success ordering.
445	    ///
446	    /// # Examples
447	    ///
448	    /// ```
449	    /// use crossbeam_epoch::{self as epoch, Atomic, Owned, Shared};
450	    /// use std::sync::atomic::Ordering::SeqCst;
451	    ///
452	    /// let a = Atomic::new(1234);
453	    ///
454	    /// let guard = &epoch::pin();
455	    /// let curr = a.load(SeqCst, guard);
456	    /// let res1 = a.compare_exchange(curr, Shared::null(), SeqCst, SeqCst, guard);
457	    /// let res2 = a.compare_exchange(curr, Owned::new(5678), SeqCst, SeqCst, guard);
458	    /// # unsafe { drop(curr.into_owned()); } // avoid leak
459	    /// ```
460	    pub fn compare_exchange<'g, P>(
461	        &self,
462	        current: Shared<'_, T>,
463	        new: P,
464	        success: Ordering,
465	        failure: Ordering,
466	        _: &'g Guard,
467	    ) -> Result<CompareExchangeValue<'g, T>, CompareExchangeError<'g, T, P>>
468	    where
469	        P: Pointer<T>,
470	    {
471	        let new = new.into_ptr();
472	        self.data
473	            .compare_exchange(current.into_ptr(), new, success, failure)
474	            .map(|old| unsafe {
475	                CompareExchangeValue {
476	                    old: Shared::from_ptr(old),
477	                    new: Shared::from_ptr(new),
478	                }
479	            })
480	            .map_err(|current| unsafe {
481	                CompareExchangeError {
482	                    current: Shared::from_ptr(current),
483	                    new: P::from_ptr(new),
484	                }
485	            })
486	    }
487	
488	    /// Stores the pointer `new` (either `Shared` or `Owned`) into the atomic pointer if the current
489	    /// value is the same as `current`. The tag is also taken into account, so two pointers to the
490	    /// same object, but with different tags, will not be considered equal.
491	    ///
492	    /// Unlike [`compare_exchange`], this method is allowed to spuriously fail even when comparison
493	    /// succeeds, which can result in more efficient code on some platforms. The return value
494	    /// contains both the previous value and the new value that was written. On success, `old`
495	    /// contains the previous value (which equals `current`) and `new` contains the value that was
496	    /// stored. On failure, `old` contains the actual current value and `new` contains the value
497	    /// that was attempted to be stored.
498	    ///
499	    /// This method takes two `Ordering` arguments to describe the memory
500	    /// ordering of this operation. `success` describes the required ordering for the
501	    /// read-modify-write operation that takes place if the comparison with `current` succeeds.
502	    /// `failure` describes the required ordering for the load operation that takes place when
503	    /// the comparison fails. Using `Acquire` as success ordering makes the store part
504	    /// of this operation `Relaxed`, and using `Release` makes the successful load
505	    /// `Relaxed`. The failure ordering can only be `SeqCst`, `Acquire` or `Relaxed`
506	    /// and must be equivalent to or weaker than the success ordering.
507	    ///
508	    /// [`compare_exchange`]: Atomic::compare_exchange
509	    ///
510	    /// # Examples
511	    ///
512	    /// ```
513	    /// use crossbeam_epoch::{self as epoch, Atomic, Owned, Shared};
514	    /// use std::sync::atomic::Ordering::SeqCst;
515	    ///
516	    /// let a = Atomic::new(1234);
517	    /// let guard = &epoch::pin();
518	    ///
519	    /// let mut new = Owned::new(5678);
520	    /// let mut ptr = a.load(SeqCst, guard);
521	    /// # unsafe { drop(a.load(SeqCst, guard).into_owned()); } // avoid leak
522	    /// loop {
523	    ///     match a.compare_exchange_weak(ptr, new, SeqCst, SeqCst, guard) {
524	    ///         Ok(result) => {
525	    ///             ptr = result.old;
526	    ///             break;
527	    ///         }
528	    ///         Err(err) => {
529	    ///             ptr = err.current;
530	    ///             new = err.new;
531	    ///         }
532	    ///     }
533	    /// }
534	    ///
535	    /// let mut curr = a.load(SeqCst, guard);
536	    /// loop {
537	    ///     match a.compare_exchange_weak(curr, Shared::null(), SeqCst, SeqCst, guard) {
538	    ///         Ok(_) => break,
539	    ///         Err(err) => curr = err.current,
540	    ///     }
541	    /// }
542	    /// # unsafe { drop(curr.into_owned()); } // avoid leak
543	    /// ```
544	    pub fn compare_exchange_weak<'g, P>(
545	        &self,
546	        current: Shared<'_, T>,
547	        new: P,
548	        success: Ordering,
549	        failure: Ordering,
550	        _: &'g Guard,
551	    ) -> Result<CompareExchangeValue<'g, T>, CompareExchangeError<'g, T, P>>
552	    where
553	        P: Pointer<T>,
554	    {
555	        let new = new.into_ptr();
556	        self.data
557	            .compare_exchange_weak(current.into_ptr(), new, success, failure)
558	            .map(|old| unsafe {
559	                CompareExchangeValue {
560	                    old: Shared::from_ptr(old),
561	                    new: Shared::from_ptr(new),
562	                }
563	            })
564	            .map_err(|current| unsafe {
565	                CompareExchangeError {
566	                    current: Shared::from_ptr(current),
567	                    new: P::from_ptr(new),
568	                }
569	            })
570	    }
571	
572	    /// Fetches the pointer, and then applies a function to it that returns a new value.
573	    /// Returns a `Result` of `Ok(previous_value)` if the function returned `Some`, else `Err(_)`.
574	    ///
575	    /// Note that the given function may be called multiple times if the value has been changed by
576	    /// other threads in the meantime, as long as the function returns `Some(_)`, but the function
577	    /// will have been applied only once to the stored value.
578	    ///
579	    /// `fetch_update` takes two [`Ordering`] arguments to describe the memory
580	    /// ordering of this operation. The first describes the required ordering for
581	    /// when the operation finally succeeds while the second describes the
582	    /// required ordering for loads. These correspond to the success and failure
583	    /// orderings of [`Atomic::compare_exchange`] respectively.
584	    ///
585	    /// Using [`Acquire`] as success ordering makes the store part of this
586	    /// operation [`Relaxed`], and using [`Release`] makes the final successful
587	    /// load [`Relaxed`]. The (failed) load ordering can only be [`SeqCst`],
588	    /// [`Acquire`] or [`Relaxed`] and must be equivalent to or weaker than the
589	    /// success ordering.
590	    ///
591	    /// [`Relaxed`]: Ordering::Relaxed
592	    /// [`Acquire`]: Ordering::Acquire
593	    /// [`Release`]: Ordering::Release
594	    /// [`SeqCst`]: Ordering::SeqCst
595	    ///
596	    /// # Examples
597	    ///
598	    /// ```
599	    /// use crossbeam_epoch::{self as epoch, Atomic};
600	    /// use std::sync::atomic::Ordering::SeqCst;
601	    ///
602	    /// let a = Atomic::new(1234);
603	    /// let guard = &epoch::pin();
604	    ///
605	    /// let res1 = a.fetch_update(SeqCst, SeqCst, guard, |x| Some(x.with_tag(1)));
606	    /// assert!(res1.is_ok());
607	    ///
608	    /// let res2 = a.fetch_update(SeqCst, SeqCst, guard, |x| None);
609	    /// assert!(res2.is_err());
610	    /// # unsafe { drop(a.into_owned()); } // avoid leak
611	    /// ```
612	    pub fn fetch_update<'g, F>(
613	        &self,
614	        set_order: Ordering,
615	        fail_order: Ordering,
616	        guard: &'g Guard,
617	        mut func: F,
618	    ) -> Result<Shared<'g, T>, Shared<'g, T>>
619	    where
620	        F: FnMut(Shared<'g, T>) -> Option<Shared<'g, T>>,
621	    {
622	        let mut prev = self.load(fail_order, guard);
623	        while let Some(next) = func(prev) {
624	            match self.compare_exchange_weak(prev, next, set_order, fail_order, guard) {
625	                Ok(result) => return Ok(result.old),
626	                Err(next_prev) => prev = next_prev.current,
627	            }
628	        }
629	        Err(prev)
630	    }
