802	    /// }
803	    ///
804	    /// impl Drop for DataStructure {
805	    ///     fn drop(&mut self) {
806	    ///         // By now the DataStructure lives only in our thread and we are sure we don't hold
807	    ///         // any Shared or & to it ourselves, but it may be null, so we have to be careful.
808	    ///         let old = mem::take(&mut self.ptr);
