1193	/// The pointer is valid for use only during the lifetime `'g`.
1194	///
1195	/// The pointer must be properly aligned. Since it is aligned, a tag can be stored into the unused
1196	/// least significant bits of the address.
1197	pub struct Shared<'g, T: 'g + ?Sized + Pointable> {
1198	    data: *mut (),
1199	    _marker: PhantomData<(&'g (), *const T)>,
1200	}
1201	
1202	impl<T: ?Sized + Pointable> Clone for Shared<'_, T> {
1203	    fn clone(&self) -> Self {
1204	        *self
1205	    }
1206	}
