1208	impl<T: ?Sized + Pointable> Copy for Shared<'_, T> {}
1209	
1210	impl<T: ?Sized + Pointable> crate::sealed::Sealed for Shared<'_, T> {}
1211	impl<T: ?Sized + Pointable> Pointer<T> for Shared<'_, T> {
1212	    #[inline]
1213	    fn into_ptr(self) -> *mut () {
1214	        self.data
1215	    }
1216	
1217	    #[inline]
1218	    unsafe fn from_ptr(data: *mut ()) -> Self {
1219	        Shared {
1220	            data,
1221	            _marker: PhantomData,
1222	        }
1223	    }
1224	}
