1226	impl<T> Shared<'_, T> {
1227	    /// Converts the pointer to a raw pointer (without the tag).
1228	    ///
1229	    /// # Examples
1230	    ///
1231	    /// ```
1232	    /// use crossbeam_epoch::{self as epoch, Atomic, Owned};
1233	    /// use std::sync::atomic::Ordering::SeqCst;
1234	    ///
1235	    /// let o = Owned::new(1234);
1236	    /// let raw = &*o as *const _;
1237	    /// let a = Atomic::from(o);
1238	    ///
1239	    /// let guard = &epoch::pin();
1240	    /// let p = a.load(SeqCst, guard);
1241	    /// assert_eq!(p.as_raw(), raw);
1242	    /// # unsafe { drop(a.into_owned()); } // avoid leak
1243	    /// ```
1244	    pub fn as_raw(&self) -> *const T {
1245	        let (raw, _) = decompose_tag::<T>(self.data);
1246	        raw as *const _
