1250	impl<'g, T: ?Sized + Pointable> Shared<'g, T> {
1251	    /// Returns a new null pointer.
1252	    ///
1253	    /// # Examples
1254	    ///
1255	    /// ```
1256	    /// use crossbeam_epoch::Shared;
1257	    ///
1258	    /// let p = Shared::<i32>::null();
1259	    /// assert!(p.is_null());
1260	    /// ```
1261	    pub const fn null() -> Self {
1262	        Self {
