1298	    /// Dereferences the pointer.
1299	    ///
1300	    /// Returns a reference to the pointee that is valid during the lifetime `'g`.
1301	    ///
1302	    /// # Safety
1303	    ///
1304	    /// Dereferencing a pointer is unsafe because it could be pointing to invalid memory.
1305	    ///
1306	    /// Another concern is the possibility of data races due to lack of proper synchronization.
1307	    /// For example, consider the following scenario:
1308	    ///
1309	    /// 1. A thread creates a new object: `a.store(Owned::new(10), Relaxed)`
1310	    /// 2. Another thread reads it: `*a.load(Relaxed, guard).as_ref().unwrap()`
1311	    ///
1312	    /// The problem is that relaxed orderings don't synchronize initialization of the object with
1313	    /// the read from the second thread. This is a data race. A possible solution would be to use
1314	    /// `Release` and `Acquire` orderings.
1315	    ///
1316	    /// # Examples
1317	    ///
1318	    /// ```
1319	    /// use crossbeam_epoch::{self as epoch, Atomic};
1320	    /// use std::sync::atomic::Ordering::SeqCst;
1321	    ///
1322	    /// let a = Atomic::new(1234);
1323	    /// let guard = &epoch::pin();
1324	    /// let p = a.load(SeqCst, guard);
1325	    /// unsafe {
1326	    ///     assert_eq!(p.deref(), &1234);
1327	    /// }
1328	    /// # unsafe { drop(a.into_owned()); } // avoid leak
1329	    /// ```
1330	    pub unsafe fn deref(&self) -> &'g T {
1331	        unsafe { &*self.as_ptr() }
1332	    }
1333	
1334	    /// Dereferences the pointer.
1335	    ///
1336	    /// Returns a mutable reference to the pointee that is valid during the lifetime `'g`.
1337	    ///
1338	    /// # Safety
1339	    ///
1340	    /// * There is no guarantee that there are no more threads attempting to read/write from/to the
1341	    ///   actual object at the same time.
1342	    ///
1343	    ///   The user must know that there are no concurrent accesses towards the object itself.
1344	    ///
1345	    /// * Other than the above, all safety concerns of `deref()` applies here.
1346	    ///
1347	    /// # Examples
1348	    ///
1349	    /// ```
1350	    /// use crossbeam_epoch::{self as epoch, Atomic};
1351	    /// use std::sync::atomic::Ordering::SeqCst;
1352	    ///
1353	    /// let a = Atomic::new(vec![1, 2, 3, 4]);
1354	    /// let guard = &epoch::pin();
1355	    ///
1356	    /// let mut p = a.load(SeqCst, guard);
1357	    /// unsafe {
1358	    ///     assert!(!p.is_null());
1359	    ///     let b = p.deref_mut();
1360	    ///     assert_eq!(b, &vec![1, 2, 3, 4]);
1361	    ///     b.push(5);
1362	    ///     assert_eq!(b, &vec![1, 2, 3, 4, 5]);
1363	    /// }
1364	    ///
1365	    /// let p = a.load(SeqCst, guard);
1366	    /// unsafe {
1367	    ///     assert_eq!(p.deref(), &vec![1, 2, 3, 4, 5]);
1368	    /// }
1369	    /// # unsafe { drop(a.into_owned()); } // avoid leak
1370	    /// ```
1371	    pub unsafe fn deref_mut(&mut self) -> &'g mut T {
1372	        unsafe { &mut *self.as_mut_ptr() }
1373	    }
