1375	    /// Converts the pointer to a reference.
1376	    ///
1377	    /// Returns `None` if the pointer is null, or else a reference to the object wrapped in `Some`.
1378	    ///
1379	    /// # Safety
1380	    ///
1381	    /// Dereferencing a pointer is unsafe because it could be pointing to invalid memory.
1382	    ///
1383	    /// Another concern is the possibility of data races due to lack of proper synchronization.
1384	    /// For example, consider the following scenario:
1385	    ///
1386	    /// 1. A thread creates a new object: `a.store(Owned::new(10), Relaxed)`
1387	    /// 2. Another thread reads it: `*a.load(Relaxed, guard).as_ref().unwrap()`
1388	    ///
1389	    /// The problem is that relaxed orderings don't synchronize initialization of the object with
1390	    /// the read from the second thread. This is a data race. A possible solution would be to use
1391	    /// `Release` and `Acquire` orderings.
1392	    ///
1393	    /// # Examples
1394	    ///
1395	    /// ```
1396	    /// use crossbeam_epoch::{self as epoch, Atomic};
1397	    /// use std::sync::atomic::Ordering::SeqCst;
1398	    ///
1399	    /// let a = Atomic::new(1234);
1400	    /// let guard = &epoch::pin();
1401	    /// let p = a.load(SeqCst, guard);
1402	    /// unsafe {
1403	    ///     assert_eq!(p.as_ref(), Some(&1234));
1404	    /// }
1405	    /// # unsafe { drop(a.into_owned()); } // avoid leak
1406	    /// ```
1407	    pub unsafe fn as_ref(&self) -> Option<&'g T> {
1408	        let (raw, _) = decompose_tag::<T>(self.data);
1409	        if raw.is_null() {
1410	            None
1411	        } else {
1412	            Some(unsafe { &*T::as_ptr(raw) })
1413	        }
1414	    }
