1464	    ///     }
1465	    /// }
1466	    /// ```
1467	    pub unsafe fn try_into_owned(self) -> Option<Owned<T>> {
1468	        if self.is_null() {
1469	            None
1470	        } else {
1471	            Some(unsafe { Owned::from_ptr(self.data) })
1472	        }
1473	    }
